def _monto_total_orden(detalles):
    total = Decimal('0')
    for detalle in detalles:
        total += Decimal(detalle.cantidad) * detalle.costo_unitario
    return total


def generar_asientos_historicos(apps, schema_editor):
    OrdenCompra = apps.get_model('compras', 'OrdenCompra')
    OrdenCompraDetalle = apps.get_model('compras', 'OrdenCompraDetalle')
