    ordenes_completadas = OrdenCompra.objects.filter(estado='CO')

    for orden in ordenes_completadas.iterator():
        detalles = OrdenCompraDetalle.objects.filter(orden_id=orden.id)
        monto_total = _monto_total_orden(detalles)

